"use client";

import * as React from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { generateForecastAction } from "@/app/actions";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "@/hooks/use-toast";
import type { ForecastState, RiskLevel } from "@/lib/types";
import { defaultData } from "@/lib/data";
import { Loader2, Zap } from "lucide-react";
import type { ProbabilisticFloodForecastOutput } from "@/ai/flows/probabilistic-flood-forecast";

const FormSchema = z.object({
  region: z.string({ required_error: "Please select a region." }),
  currentMeteorologicalDataSummary: z.string().min(10, "Please provide a more detailed summary."),
  currentHydrologicalDataSummary: z.string().min(10, "Please provide a more detailed summary."),
  historicalDisasterDataSummary: z.string().min(10, "Please provide a more detailed summary."),
  satelliteImageryAnalysisSummary: z.string().min(10, "Please provide a more detailed summary."),
});

type FormValues = z.infer<typeof FormSchema>;

interface ForecastCardProps {
  initialForecast: ForecastState;
}

export function ForecastCard({ initialForecast }: ForecastCardProps) {
  const [forecastState, setForecastState] = React.useState<ForecastState>(initialForecast);
  const [activeTab, setActiveTab] = React.useState<'form' | 'result'>('form');

  const form = useForm<FormValues>({
    resolver: zodResolver(FormSchema),
    defaultValues: {
      region: "",
      ...defaultData,
    },
  });

  const onSubmit = async (data: FormValues) => {
    setForecastState({ status: 'loading', data: null, error: null });
    setActiveTab('result');

    const result = await generateForecastAction({
      region: data.region,
      currentMeteorologicalDataSummary: data.currentMeteorologicalDataSummary,
      currentHydrologicalDataSummary: data.currentHydrologicalDataSummary,
      historicalDisasterDataSummary: data.historicalDisasterDataSummary,
      satelliteImageryAnalysisSummary: data.satelliteImageryAnalysisSummary,
    });

    if (result.success) {
      setForecastState({ status: 'succeeded', data: result.data!, error: null });

      toast({
        title: "Forecast Generated",
        description: `Successfully generated forecast for ${result.data.forecastRegion}.`,
      });
    } else {
      setForecastState({ status: 'failed', data: null, error: result.error });
      toast({
        variant: "destructive",
        title: "Forecast Failed",
        description: result.error || "An unknown error occurred.",
      });
    }
  };

  const riskLevelToColor = {
    'No Flood': 'text-green-600',
    'Moderate': 'text-yellow-600',
    'High': 'text-orange-600',
    'Extreme': 'text-red-700'
  };

  return (
    <Card>
      <CardHeader>
        <div className="flex justify-between items-start">
          <div>
            <CardTitle className="font-headline text-xl font-semibold">Probabilistic Flood Forecast</CardTitle>
            <CardDescription>Generate a 24-72 hour forecast using multi-source data.</CardDescription>
          </div>
          <div className="flex gap-1 rounded-lg bg-muted p-1 text-sm">
            <Button variant={activeTab === 'form' ? 'secondary' : 'ghost'} size="sm" onClick={() => setActiveTab('form')} className="px-3">Generator</Button>
            <Button variant={activeTab === 'result' ? 'secondary' : 'ghost'} size="sm" onClick={() => setActiveTab('result')} className="px-3" disabled={forecastState.status === 'idle'}>Result</Button>
          </div>
        </div>
      </CardHeader>
      
      {activeTab === 'form' && (
        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)}>
            <CardContent className="space-y-4">
              <FormField
                control={form.control}
                name="region"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Pilot District</FormLabel>
                    <Select onValueChange={(value) => {
                      field.onChange(value);
                      form.setValue('currentMeteorologicalDataSummary', defaultData[value as keyof typeof defaultData].currentMeteorologicalDataSummary);
                      form.setValue('currentHydrologicalDataSummary', defaultData[value as keyof typeof defaultData].currentHydrologicalDataSummary);
                      form.setValue('historicalDisasterDataSummary', defaultData[value as keyof typeof defaultData].historicalDisasterDataSummary);
                      form.setValue('satelliteImageryAnalysisSummary', defaultData[value as keyof typeof defaultData].satelliteImageryAnalysisSummary);
                    }} defaultValue={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue placeholder="Select a district to forecast" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        <SelectItem value="Lusaka">Lusaka</SelectItem>
                        <SelectItem value="Mongu">Mongu</SelectItem>
                        <SelectItem value="Chipata">Chipata</SelectItem>
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <FormField control={form.control} name="currentMeteorologicalDataSummary" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Meteorological Data</FormLabel>
                    <FormControl><Textarea placeholder="Rainfall, temperature..." {...field} rows={3}/></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
                <FormField control={form.control} name="currentHydrologicalDataSummary" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Hydrological Data</FormLabel>
                    <FormControl><Textarea placeholder="River levels, streamflow..." {...field} rows={3}/></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
                <FormField control={form.control} name="historicalDisasterDataSummary" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Historical Data</FormLabel>
                    <FormControl><Textarea placeholder="Past flood events..." {...field} rows={3}/></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
                <FormField control={form.control} name="satelliteImageryAnalysisSummary" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Satellite Imagery Analysis</FormLabel>
                    <FormControl><Textarea placeholder="Saturated ground, water expansion..." {...field} rows={3}/></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
              </div>
            </CardContent>
            <CardFooter>
              <Button type="submit" disabled={forecastState.status === 'loading'} className="w-full">
                {forecastState.status === 'loading' ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Zap className="mr-2 h-4 w-4" />}
                Generate Forecast
              </Button>
            </CardFooter>
          </form>
        </Form>
      )}

      {activeTab === 'result' && (
        <CardContent>
          {forecastState.status === 'loading' && (
            <div className="flex flex-col items-center justify-center text-center p-8 space-y-4">
              <Loader2 className="h-12 w-12 animate-spin text-primary" />
              <p className="font-semibold font-headline">Generating forecast...</p>
              <p className="text-sm text-muted-foreground">The model is analyzing the data. This might take a moment.</p>
            </div>
          )}
          {forecastState.status === 'failed' && (
            <div className="flex flex-col items-center justify-center text-center p-8 space-y-4">
              <p className="font-semibold text-destructive">Error</p>
              <p className="text-sm text-muted-foreground">{forecastState.error}</p>
              <Button onClick={() => setActiveTab('form')}>Try Again</Button>
            </div>
          )}
          {forecastState.status === 'succeeded' && forecastState.data && (
            <div className="space-y-6 p-4">
              <div className="text-center">
                <p className="text-sm text-muted-foreground">Forecast for</p>
                <h3 className="font-headline text-2xl font-bold">{forecastState.data.forecastRegion}</h3>
                <p className="text-xs text-muted-foreground">Generated: {new Date(forecastState.data.forecastTimeUTC).toLocaleString()}</p>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-center">
                <div className="bg-muted/50 p-4 rounded-lg">
                  <p className="text-sm font-medium text-muted-foreground">Risk Classification</p>
                  <p className={`font-headline text-3xl font-bold ${riskLevelToColor[forecastState.data.riskClassification]}`}>{forecastState.data.riskClassification}</p>
                </div>
                 <div className="bg-muted/50 p-4 rounded-lg">
                  <p className="text-sm font-medium text-muted-foreground">Flood Probability</p>
                  <p className="font-headline text-3xl font-bold">{(forecastState.data.floodProbability * 100).toFixed(1)}%</p>
                  <p className="text-xs text-muted-foreground">CI: [{(forecastState.data.confidenceIntervalLower*100).toFixed(0)}%-{(forecastState.data.confidenceIntervalUpper*100).toFixed(0)}%]</p>
                </div>
              </div>
              <div>
                <h4 className="font-semibold mb-2 font-headline">Justification</h4>
                <p className="text-sm text-muted-foreground bg-muted/50 p-4 rounded-lg border">{forecastState.data.justification}</p>
              </div>
              <Button onClick={() => setActiveTab('form')} className="w-full" variant="outline">Generate Another Forecast</Button>
            </div>
          )}
        </CardContent>
      )}
    </Card>
  );
}
